  ('aboriginal-6f0ba476-moex-00510', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-3e700a6a', 'sub-aboriginal-6f0ba476-07', NULL, 'single_choice', '在總稅收不變的情況下，進行「綠色租稅改革（greentaxreform）」，適合下列何者進行分析？', '["絕對租稅歸宿分析", "差異租稅歸宿分析", "絕對支出歸宿分析", "平衡預算歸宿分析"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "97b634a9eebd", "answer_pdf_sha1": "58b48eb3b056", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00511', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-3e700a6a', 'sub-aboriginal-6f0ba476-07', NULL, 'single_choice', '假設政府對一追求利潤極大化之完全競爭市場的廠商課徵利潤稅，下列敘述何者正確？', '["短期之利潤稅稅負由擁有超額利潤的廠商承擔", "短期之利潤稅稅負由消費者承擔", "長期之利潤稅稅負由擁有超額利潤的廠商承擔", "長期之利潤稅稅負由消費者承擔"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "97b634a9eebd", "answer_pdf_sha1": "58b48eb3b056", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00512', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-3e700a6a', 'sub-aboriginal-6f0ba476-07', NULL, 'single_choice', '在哈柏格（A.C.Harberger）之租稅歸宿的一般均衡模型中，假設資本和勞動並非完全不能替代， 若只對相對較勞動密集部門的資本課稅，在要素替代效果小於產出效果的情況下，資本相對於勞 動的價格和稅前比較會如何改變？', '["提高", "降低", "不變", "不一定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "97b634a9eebd", "answer_pdf_sha1": "58b48eb3b056", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00513', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-3e700a6a', 'sub-aboriginal-6f0ba476-07', NULL, 'single_choice', '假設財貨市場為完全競爭且邊際成本固定不變，關於政府課徵商品稅產生之超額負擔的衡量，下 列敘述何者錯誤？', '["若受補償需求的價格彈性絕對值愈大，則超額負擔愈大", "若稅率愈高，則超額負擔愈大", "稅前消費者花在x的支出愈多，則超額負擔愈大", "$1稅收增加造成的邊際超額負擔，小於$1稅收增加造成的平均超額負擔"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "97b634a9eebd", "answer_pdf_sha1": "58b48eb3b056", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00514', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-3e700a6a', 'sub-aboriginal-6f0ba476-07', NULL, 'single_choice', '假設小麥和玉米的市場為完全競爭且邊際成本固定不變，兩者互為替代品，政府原本只對小麥的 消費補貼，現對玉米的消費也補貼，下列敘述何者正確？', '["超額負擔一定增加", "超額負擔一定減少", "政府補貼支出一定增加", "超額負擔和政府補貼支出都不確定會增加或減少"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "97b634a9eebd", "answer_pdf_sha1": "58b48eb3b056", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00515', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-3e700a6a', 'sub-aboriginal-6f0ba476-07', NULL, 'single_choice', '假設某一勞動市場為完全競爭，政府對勞動所得課徵稅率15%的租稅，租稅完全由勞動者負擔， 受補償勞動供給對工資率的彈性為0.4，課稅前工資率為$250，勞動供給量為400,000單位。因為 課稅引起的超額負擔為多少？', '["$900,000", "$450,000", "$225,000", "$200,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "97b634a9eebd", "answer_pdf_sha1": "58b48eb3b056", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00516', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-3e700a6a', 'sub-aboriginal-6f0ba476-07', NULL, 'single_choice', '若一完全競爭市場的供給曲線為P=2Q，而需求曲線為P=240-Q。生產過程會產生負的外部性， 邊際外部成本為MEC=Q。政府為了矯正此一外部性，對每單位產品課30元的矯正稅。在此一矯 正稅下，社會福利的無謂損失是多少？', '["50", "100", "150", "200"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "97b634a9eebd", "answer_pdf_sha1": "58b48eb3b056", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00517', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-3e700a6a', 'sub-aboriginal-6f0ba476-07', NULL, 'single_choice', '假設有X、Y和休閒三樣商品，關於RamseyRule之敘述，下列何者錯誤？', '["租稅的課徵應使X和Y的受補償需求量減少相同的百分比", "應用於存在無法課稅的商品時", "使對X和Y課稅產生的總超額負擔最小", "必須假設X、Y和休閒之間不是替代也不是互補關係"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "97b634a9eebd", "answer_pdf_sha1": "58b48eb3b056", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00518', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-3e700a6a', 'sub-aboriginal-6f0ba476-07', NULL, 'single_choice', '甲是進口菸的供應商，他的香菸來源有合法進口也有走私，若政府提高香菸的稅率，其他條件不 變，下列敘述何者正確？', '["甲會進口更多的香菸", "甲會走私更多的香菸", "對甲沒有影響", "政府稅收一定增加"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "97b634a9eebd", "answer_pdf_sha1": "58b48eb3b056", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00519', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-3e700a6a', 'sub-aboriginal-6f0ba476-07', NULL, 'single_choice', '下列何種情形，課徵薪資所得稅不會降低勞動者的工作意願？', '["休閒為正常財，且所得效果小於替代效果", "休閒為正常財，且所得效果大於替代效果", "休閒為劣等財，且所得效果小於替代效果", "休閒為劣等財，且所得效果大於替代效果"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "97b634a9eebd", "answer_pdf_sha1": "58b48eb3b056", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL)
